sql:
SELECT AVG(length) AS average_length
FROM newborns
WHERE low_birth_weight = 'low';

SELECT * 
FROM pregnancy_records
WHERE mother_age < 25 AND smoking_habit = 'smoker';

SELECT AVG(mother_age) 
FROM pregnancy_records 
WHERE low_birth_weight = 'yes';

SELECT COUNT(*) 
FROM newborns 
WHERE low_birth_weight = 'low';

SELECT smoking_habit
FROM mothers
WHERE (age > 30 AND ethnicity = 'white') OR occupation = 'Student';

external_knowledge:
- "blossoming young" refers to mothers aged 18-25;
- "mature adults" refers to mothers aged 26-32;
- "seasoned mothers" refers to mothers aged 33-39;
- "grandmothers" refers to mothers who are 40 and above;
- "rendezvous with the medical practitioners" metaphorically refers to doctor appointments.

